SELECT ,
FROM user_coupons uc LEFT JOIN coupons c ON uc.coupon_id = c.id WHERE uc.deleted_at IS NULL AND uc.user_id = #{userId}
AND uc.status = #{status}
ORDER BY uc.created_at DESC

SELECT
,

FROM user_coupons uc
INNER JOIN coupons c ON uc.coupon_id = c.id
WHERE uc.deleted_at IS NULL
  AND c.deleted_at IS NULL
  AND uc.user_id = #{userId}
  AND uc.status = 0
  AND c.valid_start_time <= #{now}
  AND c.valid_end_time >= #{now}
  AND c.min_amount <= #{orderAmount}
ORDER BY c.min_amount DESC, c.amount DESC, c.discount ASC
